INSERT INTO projects (title,slug,stall_area_sqm,stall_area_sqft,stall_height_m,floors,build_year,city,exhibition_id,client_id,description,design_brief,ai_summary,design_style,materials_used,special_features,awards,status,is_featured,display_order) VALUES ('Wian 12 SQM 2 Side Open Stall Exhibition Stall Design at FITAG Tech Expo - IT Show, Gandhinagar 2025','wian-12-sqm-custom-exhibition-stall-fitag-tech-expo-it-show-gandhinagar-2025',12,129.17,4,1,2025,'Gandhinagar',(SELECT id FROM exhibitions WHERE slug='fitag-tech-expo-it-show'),(SELECT id FROM clients WHERE slug='wian'),'Approach Media designed and fabricated a 12 SQM 2 side open stall exhibition stall for Wian at FITAG Tech Expo - IT Show, Helipad Ground, Gandhinagar. The booth presents a compact Wian stall with a blue-white illuminated fascia, product display cabinet, consultation counter, and a tidy two-side open technology display format. The stall was planned for strong brand recall, clear product visibility, easy visitor movement, and search-friendly portfolio discovery for security devises, it, hardware, television exhibition projects in Gandhinagar, India.','Create a 12 SQM 2 side open stall custom exhibition stall for Wian that communicates technology, product credibility, and visitor engagement at FITAG Tech Expo - IT Show. The design needed visible branding, product-led storytelling, practical discussion areas, and a premium finish suitable for a busy expo environment.','Wian exhibition stall by Approach Media at FITAG Tech Expo - IT Show, Gandhinagar: 12 SQM 2 side open stall booth with compact blue-white technology display booth, designed for product display, lead generation, visitor interaction, and high search relevance around custom exhibition stall design and fabrication in Gujarat.','Compact blue-white technology display booth','["Wooden modular panels", "laminate finish", "printed vinyl graphics", "acrylic signage", "LED lighting", "display shelves"]','["Two-side open compact stall", "illuminated blue fascia", "product display counter", "wall graphics", "visitor interaction desk"]',NULL,'published',true,70) ON CONFLICT (slug) DO NOTHING;
